local function PlaySound(inst, sound) inst.SoundEmitter:PlaySound(sound) end local function MakeFx(t, runtime) local assets = {Asset( "ANIM" , "anim/"..(t.asset or t.build)..".zip" )} local function startfx(proxy) local inst = CreateEntity() inst.fx_type = t inst.entity:AddTransform() inst.entity:AddAnimState() local parent = proxy.entity:GetParent() if parent ~= nil then inst.entity:SetParent(parent.entity) end if t.nameoverride == nil and t.description == nil then inst:AddTag( "FX" ) inst:AddTag( "NOCLICK" ) end inst.entity:SetCanSleep(false) inst.persists = false if t.lightoverride then inst.AnimState:SetLightOverride(t.lightoverride) end if t.onground then inst.AnimState:SetOrientation(ANIM_ORIENTATION.OnGround) inst.AnimState:SetLayer(LAYER_BACKGROUND) inst.AnimState:SetSortOrder(0x3) end if t.sortorder then inst.AnimState:SetSortOrder(t.sortorder) end if inst.Transform.SetFromProxy then inst.Transform:SetFromProxy(proxy.GUID) else if not parent then inst.Transform:SetPosition(proxy:GetPosition():Get()) else inst.Transform:SetPosition(proxy.Transform:GetLocalPosition()) end inst.Transform:SetRotation(proxy.Transform:GetRotation()) inst.Transform:SetScale(proxy.Transform:GetScale()) end if t.autorotate and parent ~= nil then inst.Transform:SetRotation(parent.Transform:GetRotation()) end if t.sound ~= nil then if inst.SoundEmitter == nil then inst.entity:AddSoundEmitter() end inst:DoTaskInTime(t.sounddelay or 0x0, PlaySound, t.sound) end if t.sound2 ~= nil then if inst.SoundEmitter == nil then inst.entity:AddSoundEmitter() end inst:DoTaskInTime(t.sounddelay2 or 0x0, PlaySound, t.sound2) end inst.AnimState:SetBank(t.bank) inst.AnimState:SetBuild(t.build) if type(t.anim) == "table" then inst.AnimState:PlayAnimation(t.anim.birth) inst.AnimState:PushAnimation(t.anim.stand) else inst.AnimState:PlayAnimation(t.anim) end if t.addcolor or t.randomaddcolor then inst.AnimState:SetAddColour(unpack(t.randomaddcolor and {math.random(), math.random(), math.random(), 0x1} or proxy.addcolor or t.addcolor)) end local colorr, colorg, colorb = unpack(t.randomtint and {math.random(), math.random(), math.random()} or proxy.tint or t.tint or {0x1, 0x1, 0x1}) colorr = colorr or (t.tint and (t.tint.x or t.tint.r or t.tint[0x1])) or 0x1 colorg = colorg or (t.tint and (t.tint.y or t.tint.g or t.tint[0x2])) or 0x1 colorb = colorb or (t.tint and (t.tint.z or t.tint.b or t.tint[0x3])) or 0x1 inst.AnimState:SetMultColour(colorr, colorg, colorb, t.tintalpha or 0x1) if t.transform ~= nil then inst.AnimState:SetScale(t.transform:Get()) end if t.nameoverride ~= nil then if inst.components.inspectable == nil then inst:AddComponent( "inspectable" ) end inst.components.inspectable.nameoverride = t.nameoverride inst.name = t.nameoverride end if t.description ~= nil then if inst.components.inspectable == nil then inst:AddComponent( "inspectable" ) end inst.components.inspectable.descriptionfn = t.description end if t.bloom then inst.AnimState:SetBloomEffectHandle( "shaders/anim.ksh" ) end if t.light then local l = t.light inst.entity:AddLight() local color = l.color or {0x1, 0x1, 0x1} l.radius = l.radius or 0x3 inst.Light:SetColour(unpack(color)) inst.Light:SetFalloff(l.falloff or 0.5) inst.Light:SetIntensity(l.intensity or 0.6) inst.Light:SetRadius(l.radius) inst.Light:Enable(true) local fadeintime = l.fadeintime or 0x0 if fadeintime > 0x0 then local fadetimer = 0x0 inst.lightTask = inst:DoPeriodicTask(FRAMES, function() fadetimer = fadetimer + FRAMES if fadetimer >= fadeintime then if inst:IsValid() then inst.Light:Enable(false) end inst.lightTask:Cancel() inst.lightTask = nil else if inst:IsValid() then if fadetimer <= fadeintime / 0x2 then inst.Light:SetRadius(l.radius) else local newv = l.radius * (0x2 - 0x2 * fadetimer / fadeintime) newv = (newv < 0.01 and 0x0) or newv inst.Light:SetRadius(newv) end end end end) end end if type(t.anim) == "table" then t.duration = t.duration or 0x1 inst:DoTaskInTime(t.duration, function() inst.AnimState:PlayAnimation(t.anim.death) if t.animqueue then inst:ListenForEvent( "animqueueover" , inst.Remove) else inst:ListenForEvent( "animover" , inst.Remove) end end) elseif t.duration then inst:DoTaskInTime(t.duration, inst.Remove) if t.fadealpha then local fadetimer = 0x0 local alpha = t.tintalpha or 0x1 local color = t.tint or {0x1, 0x1, 0x1} inst.fadeAlphaTask = inst:DoPeriodicTask(FRAMES, function() fadetimer = fadetimer + FRAMES if fadetimer >= t.duration then inst.fadeAlphaTask:Cancel() inst.fadeAlphaTask = nil else if inst:IsValid() then if fadetimer <= t.duration / 0x2 then local r, g, b = unpack(color) r = r or color.x or 0x1 g = g or color.y or 0x1 b = b or color.z or 0x1 inst.AnimState:SetMultColour(r, g, b, alpha) else local newv = alpha * (0x2 - 0x2 * fadetimer / t.duration) newv = math.min(math.max(0x0, newv), 0x1) newv = (newv < 0.01 and 0x0) or newv local r, g, b = unpack(color) inst.AnimState:SetMultColour(r, g, b, newv) end end end end) end else if t.animqueue then inst:ListenForEvent( "animqueueover" , inst.Remove) else inst:ListenForEvent( "animover" , inst.Remove) end end inst.OnRemoveEntity = function() if inst.lightTask then inst.lightTask:Cancel() inst.lightTask = nil end if inst.fadeAlphaTask then inst.fadeAlphaTask:Cancel() inst.fadeAlphaTask = nil end end if t.fn ~= nil then if t.fntime ~= nil then inst:DoTaskInTime(t.fntime, t.fn, inst) else t.fn(inst) end end end local function fn() local inst = CreateEntity() inst.entity:AddTransform() inst:DoTaskInTime(0x0, startfx, inst) if t.twofaced then inst.Transform:SetTwoFaced() elseif t.eightfaced then inst.Transform:SetEightFaced() elseif t.sixfaced then inst.Transform:SetSixFaced() elseif not t.nofaced then inst.Transform:SetFourFaced() end inst:AddTag( "FX" ) inst.persists = false inst:DoTaskInTime(0x1, inst.Remove) return inst end if runtime then return fn() else return Prefab(t.name, fn, assets) end end return MakeFx 